('guide.home.title', 'Planning to Buy in Zichron Yaakov?', 'שוקלים לקנות בית בזכרון יעקב?', 'home', 'guide'),
('guide.home.hook', 'Start with the Zichron Yaakov Buyer Blueprint — a practical guide created for English-speaking buyers researching property in the Moshava.', 'רוב האנשים שמגיעים לחפש בית בזכרון יעקב לא מכירים את ההבדלים האמיתיים בין השכונות — וזה יכול לעלות מאות אלפי שקלים.', 'home', 'guide'),
('guide.home.intro', 'A practical guide to help you navigate the local market with confidence.', 'לכן יצרנו את המדריך לרוכשי בתים בזכרון יעקב.', 'home', 'guide'),
